// ─────────────────────────────────────────────
// Helper: build product object
// ─────────────────────────────────────────────
function makeProduct(item, sellerId, catId, idx) {
  return {
    seller: sellerId,
    name: item.name,
    description: item.desc,
    basePrice: item.price,
    discountPrice: item.price - Math.round(item.price * ([5, 10, 15, 20, 25][idx % 5] / 100)),
    category: catId,
    images: [item.img],
    rating: item.rating || (3.8 + (idx % 12) * 0.1),
    numReviews: Math.floor(Math.random() * 300) + 10,
    specifications: item.specs || [],
    featured: item.featured || idx < 3,
    trending: item.trending || false,
    bestSeller: item.bestSeller || false,
    newArrival: item.newArrival || false,
    isApproved: true,
    variants: [
      { color: 'Default', size: 'Standard', price: item.price, stock: Math.floor(Math.random() * 50) + 10 }
    ]
  };
}

